// Add comprehensive logging to track message lifecycle
class MessageTracker {
  constructor() {
    this.messageLog = new Map();
  }

  logOutbound(messageId, recipient, content, timestamp) {
    this.messageLog.set(messageId, {
      type: 'outbound',
      recipient,
      content,
      timestamp,
      status: 'sent'
    });
  }

  logDeliveryStatus(messageId, status, timestamp) {
    const message = this.messageLog.get(messageId);
    if (message) {
      message.deliveryStatus = status;
      message.deliveredAt = timestamp;
    }
  }

  logInbound(sender, content, timestamp) {
    const inboundId = `inbound_${timestamp}_${sender}`;
    this.messageLog.set(inboundId, {
      type: 'inbound',
      sender,
      content,
      timestamp
    });
  }

  analyzePatterns() {
    const messages = Array.from(this.messageLog.values());

    // Check for spam patterns
    const spamIndicators = this.detectSpamPatterns(messages);

    // Check delivery failures
    const deliveryIssues = this.analyzeDeliveryFailures(messages);

    return { spamIndicators, deliveryIssues };
  }

  detectSpamPatterns(messages) {
    const outbound = messages.filter(m => m.type === 'outbound');

    // Check for duplicate messages
    const duplicates = this.findDuplicateMessages(outbound);

    // Check for rapid-fire messaging
    const rapidMessages = this.findRapidMessages(outbound);

    // Check for messages outside business hours
    const offHoursMessages = this.findOffHoursMessages(outbound);

    return { duplicates, rapidMessages, offHoursMessages };
  }
}
```

