    if (!verifySignature(req.body, signature)) {
      console.error('Invalid webhook signature');
      return res.status(401).send('Unauthorized');
    }

    // Process each message
    const messages = req.body.entry?.[0]?.changes?.[0]?.value?.messages || [];

    messages.forEach(message => {
      console.log(`Processing message: ${message.id} from ${message.from}`);

      // Check if this is a duplicate
      if (processedMessages.has(message.id)) {
        console.warn(`Duplicate message detected: ${message.id}`);
        return;
      }

      processedMessages.add(message.id);

      // Process with timeout
      Promise.race([
        processMessage(message),
        new Promise((_, reject) => 
          setTimeout(() => reject(new Error('Processing timeout')), 5000)
        )
      ]).catch(error => {
        console.error(`Message processing failed for ${message.id}:`, error);
      });
    });

    console.log(`Webhook processed in ${Date.now() - startTime}ms`);
    res.status(200).send('OK');

  } catch (error) {
    console.error('Webhook processing error:', error);
    res.status(500).send('Internal Server Error');
