## Step 3: Spam Investigation

### Duplicate Message Detection
```javascript
class DuplicateDetector {
  constructor() {
    this.sentMessages = new Map();
    this.cleanupInterval = setInterval(() => this.cleanup(), 300000); // 5 min
  }

  checkDuplicate(recipient, content, timeWindow = 60000) {
    const key = `${recipient}:${this.hashContent(content)}`;
    const now = Date.now();

    if (this.sentMessages.has(key)) {
      const lastSent = this.sentMessages.get(key);
      if (now - lastSent < timeWindow) {
        console.warn(`Duplicate message prevented to ${recipient}`);
        return true;
      }
    }

    this.sentMessages.set(key, now);
    return false;
  }

  hashContent(content) {
    return require('crypto')
      .createHash('md5')
      .update(JSON.stringify(content))
      .digest('hex');
  }

  cleanup() {
    const now = Date.now();
    const maxAge = 3600000; // 1 hour

    for (const [key, timestamp] of this.sentMessages) {
      if (now - timestamp > maxAge) {
        this.sentMessages.delete(key);
      }
    }
  }
}
```

